// ---- Utility functions ----

function getClaudeDir() {
  var home = process.env.HOME || process.env.USERPROFILE;
  return path.join(home, ".claude");
}

function mkdirp(dir) {
  if (!fs.existsSync(dir)) { fs.mkdirSync(dir, { recursive: true }); }
}

function rmrf(dir) {
  if (!fs.existsSync(dir)) return;
  var entries = fs.readdirSync(dir);
  for (var i = 0; i < entries.length; i++) {
    var p = path.join(dir, entries[i]);
    if (fs.statSync(p).isDirectory()) { rmrf(p); } else { fs.unlinkSync(p); }
  }
  fs.rmdirSync(dir);
}

function sha256(filePath) {
  return crypto.createHash("sha256").update(fs.readFileSync(filePath)).digest("hex");
}

function runCli(args) {
  try {
    var result = childProcess.execFileSync("claude", args.split(" "), {
      encoding: "utf8", timeout: 30000, stdio: ["pipe", "pipe", "pipe"]
    });
    return { ok: true, output: result.trim() };
  } catch (e) {
    return { ok: false, output: (e.stderr || e.message || "").trim() };
  }
}

function log(msg) { console.log("[install] " + msg); }
function logOk(msg) { console.log("[install] \u2714 " + msg); }
function logErr(msg) { console.error("[install] \u2718 " + msg); }

// ---- Install ----

function install() {
  console.log("");
  console.log("  Claude Model Changer v" + PLUGIN_VERSION);
  console.log("  ===================================");
  console.log("  Automatic model routing for Claude Code");
  console.log("  Files: " + FILE_COUNT + " | Marketplace: " + MARKETPLACE_NAME + " (" + MARKETPLACE_OWNER_SOURCE + ")");
  console.log("");

  var claudeDir = getClaudeDir();
  if (!fs.existsSync(claudeDir)) {
    logErr("Claude Code directory not found: " + claudeDir);
    logErr("Install Claude Code first: https://claude.ai/download");
    process.exit(1);
  }

  // Step 1: Create marketplace structure
  log("Creating marketplace structure...");
  var marketplaceDir = path.join(claudeDir, "plugins", "marketplaces", MARKETPLACE_NAME);
  var pluginDir = path.join(marketplaceDir, "plugins", PLUGIN_NAME);
  mkdirp(path.join(marketplaceDir, ".claude-plugin"));
  mkdirp(pluginDir);
  fs.writeFileSync(path.join(marketplaceDir, ".claude-plugin", "marketplace.json"), buildMarketplaceJson());
  logOk("Marketplace created");

  // Step 2: Extract plugin files
  log("Extracting " + FILE_COUNT + " plugin files...");
  var extracted = 0;
  FILES.forEach(function(f) {
    var destPath = path.join(pluginDir, f.path);
    mkdirp(path.dirname(destPath));
    fs.writeFileSync(destPath, Buffer.from(f.content, "base64"));
    extracted++;
  });
  mkdirp(path.join(pluginDir, "logs"));
  logOk("Extracted " + extracted + " files");

  // Step 3: Try CLI-based installation
  log("Registering via CLI...");
  var cliOk = runCli("--version").ok;
  var installed = false;

  if (cliOk) {
    runCli("plugin marketplace add " + marketplaceDir);
    var r = runCli("plugin install " + PLUGIN_KEY);
    if (r.ok || r.output.indexOf("already") !== -1) {
      logOk("Plugin installed via CLI");
      installed = true;
    }
  }

  if (!installed) {
    log("CLI not available, using manual registration...");
    manualRegister(claudeDir);
  }

  // Step 4: Generate manifest
  log("Generating file integrity manifest...");
  var cacheDir = path.join(claudeDir, "plugins", "cache", MARKETPLACE_NAME, PLUGIN_NAME, PLUGIN_VERSION);
  var sourceDir = fs.existsSync(cacheDir) ? cacheDir : pluginDir;
  var manifestDir = path.join(claudeDir, "plugins", ".install-manifests");
  mkdirp(manifestDir);
  var manifest = { pluginId: PLUGIN_KEY, createdAt: new Date().toISOString(), files: {} };
  FILES.forEach(function(f) {
    var fp = path.join(sourceDir, f.path);
    if (fs.existsSync(fp)) { manifest.files[f.path.replace(/\//g, "\\\\")] = sha256(fp); }
  });
  fs.writeFileSync(path.join(manifestDir, PLUGIN_KEY + ".json"), JSON.stringify(manifest, null, 2));
  logOk("Manifest: " + Object.keys(manifest.files).length + " file hashes");

  console.log("");
  console.log("  \u2714 Installation complete!");
  console.log("  Restart Claude Code to activate.");
  console.log("");
  console.log("  Commands: /stats /configure /complexity /benchmark /dashboard /tune /rate");
  console.log("  Override: @haiku @sonnet @opus");
  console.log("  Auto-routing is active on every prompt.");
  console.log("");
}

// v3.6.1: Remove orphan version directories from prior installs.
// Each install lives under .../<MARKETPLACE>/<PLUGIN_NAME>/<VERSION>/ —
// older versions were never cleaned up, so 3.4.2, 3.5.0, 3.6.0 would
// accumulate side-by-side and waste a few MB per release. This sweeps
// everything in the parent dir except the version we are installing.
// External skill cache (cache/<owner>/external/) is intentionally
// untouched — it lives in a different parent and is shared across
// versions for the smart-skip sync logic.
function cleanupOldVersions(cacheDir) {
  var parent = path.dirname(cacheDir);
  if (!fs.existsSync(parent)) return;
  var entries;
  try { entries = fs.readdirSync(parent); } catch (e) { return; }
  var removed = 0;
  for (var i = 0; i < entries.length; i++) {
    var name = entries[i];
    if (name === PLUGIN_VERSION) continue;
    // Only touch entries that look like SemVer version dirs to be safe.
    if (!/^\d+\.\d+\.\d+([.\-+].*)?$/.test(name)) continue;
    var p = path.join(parent, name);
    try {
      if (fs.statSync(p).isDirectory()) {
        rmrf(p);
        logOk("Removed orphan v" + name);
        removed++;
      }
    } catch (e) { /* skip on permission error etc. */ }
  }
  if (removed === 0) return;
  // Also prune stale entries from installed_plugins.json that point to
  // the now-deleted version dirs (same plugin, different version).
  try {
    var pfPath = path.join(getClaudeDir(), "plugins", "installed_plugins.json");
    if (!fs.existsSync(pfPath)) return;
    var pdRaw = JSON.parse(fs.readFileSync(pfPath, "utf8"));
    if (!pdRaw.plugins || !pdRaw.plugins[PLUGIN_KEY]) return;
    pdRaw.plugins[PLUGIN_KEY] = pdRaw.plugins[PLUGIN_KEY].filter(function (e) {
      return e && e.version === PLUGIN_VERSION;
    });
    fs.writeFileSync(pfPath, JSON.stringify(pdRaw, null, 2));
  } catch (e) { /* never block install on bookkeeping */ }
}

function manualRegister(claudeDir) {
  var cacheDir = path.join(claudeDir, "plugins", "cache", MARKETPLACE_NAME, PLUGIN_NAME, PLUGIN_VERSION);
  cleanupOldVersions(cacheDir);
  mkdirp(cacheDir);
  FILES.forEach(function(f) {
    var dp = path.join(cacheDir, f.path);
    mkdirp(path.dirname(dp));
    fs.writeFileSync(dp, Buffer.from(f.content, "base64"));
  });
  mkdirp(path.join(cacheDir, "logs"));
  fs.writeFileSync(path.join(cacheDir, ".cli-installed"), new Date().toISOString() + "\n");
  fs.writeFileSync(path.join(cacheDir, ".install-version"),
    JSON.stringify({ version: PLUGIN_VERSION, bun: null, uv: null, installedAt: new Date().toISOString() }));

  var pf = path.join(claudeDir, "plugins", "installed_plugins.json");
  var pd = { version: 2, plugins: {} };
  try { if (fs.existsSync(pf)) pd = JSON.parse(fs.readFileSync(pf, "utf8")); } catch(e) {}
  if (!pd.plugins) pd.plugins = {};
  pd.plugins[PLUGIN_KEY] = [{ scope: "user", installPath: cacheDir, version: PLUGIN_VERSION,
    installedAt: new Date().toISOString(), lastUpdated: new Date().toISOString() }];
  // Migrate: drop legacy "@local" entry from older buggy installs
  if (LEGACY_PLUGIN_KEY !== PLUGIN_KEY && pd.plugins[LEGACY_PLUGIN_KEY]) {
    delete pd.plugins[LEGACY_PLUGIN_KEY];
    logOk("Removed legacy " + LEGACY_PLUGIN_KEY + " entry");
  }
  mkdirp(path.dirname(pf));
  fs.writeFileSync(pf, JSON.stringify(pd, null, 2));

  var sf = path.join(claudeDir, "settings.json");
  var s = {};
  try { if (fs.existsSync(sf)) s = JSON.parse(fs.readFileSync(sf, "utf8")); } catch(e) {}
  if (!s.enabledPlugins) s.enabledPlugins = {};
  s.enabledPlugins[PLUGIN_KEY] = true;
  if (LEGACY_PLUGIN_KEY !== PLUGIN_KEY && s.enabledPlugins[LEGACY_PLUGIN_KEY]) {
    delete s.enabledPlugins[LEGACY_PLUGIN_KEY];
  }
  // v3.7.1: wire the terminal statusline so the routed model / context% /
  // quota% / cost show in the Claude Code status bar. Absolute path to this
  // install (CLAUDE_PLUGIN_ROOT is not reliably expanded in a statusLine
  // command); kept current by plugin-self-update.js on each version change.
  // Conservative: only set if absent or already ours — a custom statusLine
  // is left untouched.
  try {
    var existingSL = s.statusLine;
    var slIsOurs = existingSL && existingSL.command &&
      existingSL.command.indexOf("statusline.js") !== -1 &&
      existingSL.command.indexOf("claude-model-changer") !== -1;
    if (!existingSL || slIsOurs) {
      s.statusLine = { type: "command", command: "node \"" + cacheDir.replace(/\\/g, "/") + "/scripts/statusline.js\"" };
      logOk("Configured terminal statusLine");
    } else {
      logOk("Custom statusLine present - left untouched");
    }
  } catch (e) { /* statusLine is best-effort */ }
  fs.writeFileSync(sf, JSON.stringify(s, null, 2));
  logOk("Manual registration complete");
}

// ---- Uninstall ----

function uninstall() {
  console.log("");
  console.log("  Claude Model Changer - Uninstaller");
  console.log("  ===================================");
  console.log("");
  var claudeDir = getClaudeDir();
  if (runCli("--version").ok) {
    runCli("plugin uninstall " + PLUGIN_KEY);
    logOk("Plugin uninstalled via CLI");
  }
  var cd = path.join(claudeDir, "plugins", "cache", MARKETPLACE_NAME, PLUGIN_NAME);
  if (fs.existsSync(cd)) { rmrf(cd); logOk("Removed cache"); }
  var mp = path.join(claudeDir, "plugins", "marketplaces", MARKETPLACE_NAME, "plugins", PLUGIN_NAME);
  if (fs.existsSync(mp)) { rmrf(mp); logOk("Removed marketplace copy"); }
  var mf = path.join(claudeDir, "plugins", ".install-manifests", PLUGIN_KEY + ".json");
  if (fs.existsSync(mf)) { fs.unlinkSync(mf); logOk("Removed manifest"); }
  try {
    var pf = path.join(claudeDir, "plugins", "installed_plugins.json");
    if (fs.existsSync(pf)) {
      var pd = JSON.parse(fs.readFileSync(pf, "utf8"));
      if (pd.plugins) { delete pd.plugins[PLUGIN_KEY]; delete pd.plugins[PLUGIN_NAME + "@local"]; }
      fs.writeFileSync(pf, JSON.stringify(pd, null, 2));
    }
  } catch(e) {}
  try {
    var sf = path.join(claudeDir, "settings.json");
    if (fs.existsSync(sf)) {
      var s = JSON.parse(fs.readFileSync(sf, "utf8"));
      if (s.enabledPlugins) { delete s.enabledPlugins[PLUGIN_KEY]; delete s.enabledPlugins[PLUGIN_NAME + "@local"]; }
      fs.writeFileSync(sf, JSON.stringify(s, null, 2));
    }
  } catch(e) {}
  console.log("");
  logOk("Uninstall complete. Restart Claude Code.");
  console.log("");
}

if (process.argv.indexOf("--uninstall") !== -1) { uninstall(); } else { install(); }